mapper.select:
SELECT t.id, t.avatar_url, t.account, t.name, t.title_id, t.pinyin_abbr, t.gender, t.phone, t.id_card, t.status, t.fixed_phone, t.email, t.qq, t.wechat, t.address, t.mailing_address, t.zip_code, t.emergency_contact, t.emergency_phone, t.birth_date, t.education, t.major, t.native_place, t.work_unit, t.nationality, t.signature, t.bio, t.recommended, t.last_login_time, t.create_time, t.update_time, t.create_by, t.update_by FROM edu_teacher t WHERE t.deleted = 0
AND t.account LIKE CONCAT('%', #{query.account}, '%')
AND t.name LIKE CONCAT('%', #{query.name}, '%')
AND t.phone LIKE CONCAT('%', #{query.phone}, '%')
AND t.title_id = #{query.titleId}
AND t.education = #{query.education}
AND t.status = #{query.status}
ORDER BY t.id ASC
